import { McpProxy } from "./mcpProxy.js";
import type { PlatformConfig } from "./platform.js";
/**
 * The shared way for a CLI command to call the plugin MCP directly. Wraps an
 * McpProxy with the active config bound in, so callers issue `client.call(tool,
 * args)` instead of repeating `new McpProxy(...)` + threading `getConfig()`
 * through every call. The MCP server uses its own internal `proxyToolCall`
 * closure; this is the equivalent for the command layer.
 *
 * Core command functions take an `McpClient` (not a concrete proxy) so tests
 * can inject a fake with `call` / `ensureSession` / `serviceUrl`.
 */
export interface McpClient {
    /** Call an MCP tool by name. Returns the proxy's tool-call result. */
    call(tool: string, args: Record<string, unknown>): ReturnType<McpProxy["toolCall"]>;
    /**
     * Establish the MCP session once up front. Call before fanning out parallel
     * `call`s so they don't each race to initialize a throwaway session.
     */
    ensureSession(): Promise<void>;
    /** The resolved Bitfab service URL the client talks to. */
    readonly serviceUrl: string;
}
/**
 * Build an McpClient bound to the active config. Reads `getConfig()` once at
 * construction (matching the previous per-runner behavior), so a command's
 * whole run uses a single config snapshot.
 */
export declare function createMcpClient(platform: PlatformConfig, pluginVersion: string): McpClient;
